import {
  Autumn
} from "./chunk-MJBKNDWD.mjs";
import {
  executeRoute
} from "./chunk-55C2WWXQ.mjs";
import {
  routeConfigs
} from "./chunk-BSY23UM3.mjs";
import {
  secretKeyCheck
} from "./chunk-VZIMT7AO.mjs";

// src/backend/core/handlers/handleRouteByName.ts
var handleRouteByName = async ({
  routeName,
  body,
  identify,
  secretKey,
  autumnURL
}) => {
  const keyCheck = secretKeyCheck(secretKey);
  if (!keyCheck.found) {
    return {
      status: keyCheck.error.statusCode,
      body: keyCheck.error
    };
  }
  const route = routeConfigs.find((r) => r.route === routeName);
  if (!route) {
    return {
      status: 404,
      body: { message: "Route not found", code: "route_not_found" }
    };
  }
  const autumn = new Autumn({
    secretKey: secretKey || process.env.AUTUMN_SECRET_KEY,
    ...autumnURL && { serverURL: autumnURL }
  });
  const result = await executeRoute({
    autumn,
    route,
    body,
    getCustomer: identify
  });
  return {
    status: result.statusCode,
    body: result.body
  };
};

export {
  handleRouteByName
};
